.darma-loader-darma-custom-636 {color: var(--loader-color, #b45309);
   width: 90px;
   height: 14px;
   box-shadow: 0 3px 0 currentColor;
   background: linear-gradient(currentColor 0 0) 50%/2px 100% no-repeat;
   display: grid;
}
.darma-loader-darma-custom-636:before, .darma-loader-darma-custom-636:after {
  content: "";
   grid-area: 1/1;
   background: radial-gradient(circle closest-side, var(--c,currentColor) 92%,#0000 ) 0 0/calc(100%/4) 100%;
   clip-path: inset(0 50% 0 0);
   animation: darma-loader-darma-custom-636-l3 1s infinite linear;
}
.darma-loader-darma-custom-636:after {
  --c: var(--loader-color, #b45309);
   clip-path: inset(0 0 0 50%);
}
@keyframes darma-loader-darma-custom-636-l3  {
  100% {background-position: calc(100%/3) 0}
}

